import type {ArticleSection} from '../types/philosophy';

const section=(id:string,title:string,paragraphs:string[],relatedBranchIds?:string[],relatedPhilosopherIds?:string[],relatedWorkTitles?:string[]):ArticleSection=>({id,title,paragraphs,relatedBranchIds,relatedPhilosopherIds,relatedWorkTitles});

export const lateAntiqueBridgePhilosopherArticles:Record<string,ArticleSection[]>={
  porphyry:[
    section('overview','The organizer who made philosophical inheritance usable',[
      'Porphyry is often introduced as Plotinus’ editor, but editing was only one expression of a larger philosophical project. He organized texts, clarified curricula, interpreted Plato and Aristotle, wrote on logic, ethics, religion, and diet, and presented philosophy as disciplined purification. His work helped later readers encounter Neoplatonism as a teachable tradition rather than a collection of one teacher’s difficult arguments.',
      'Porphyry also stands at a crossroads. He preserves Plotinus while sometimes giving the inheritance a more orderly and accessible form. He transmits Aristotelian logic into later Platonist and medieval education. He defends pagan philosophical practice while criticizing Christianity. His importance lies in mediation that changes what it carries: arrangement, introduction, commentary, and biography determine which questions later traditions can ask.'
    ],['neoplatonism','platonism','aristotelianism','logic'],['porphyry','plotinus','aristotle'],['Isagoge','Life of Plotinus']),
    section('context','A late antique world of schools, texts, and religious rivalry',[
      'Porphyry lived in the third-century Roman Empire, when Platonists, Aristotelians, Stoic inheritances, Christian communities, and diverse religious practices competed over philosophy, revelation, and the good life. Education depended increasingly on reading authoritative texts through organized sequences and commentary. A philosopher needed not only arguments but a method for deciding how inherited works fit together and how students should move from logic toward ethics and metaphysics.',
      'Born in Tyre and educated in several intellectual centers, Porphyry joined Plotinus’ circle in Rome. His career shows that late antique philosophy was mobile and multilingual, crossing regions while constructing lineages back to Greek authorities. The setting explains his range. Logic clarifies discourse; biography presents an exemplary life; ascetic practice disciplines embodiment; metaphysics orders reality; religious controversy asks which traditions can claim rational and saving authority.'
    ],['neoplatonism','platonism','philosophy-of-religion'],['porphyry','plotinus'],[]),
    section('plotinus','Student, critic, and interpreter of Plotinus',[
      'Porphyry’s Life of Plotinus portrays his teacher as contemplative, generous, philosophically rigorous, and reluctant to identify himself with bodily appearance. It also records seminars, disputes, students, illnesses, and Porphyry’s own intellectual crisis. The biography is not neutral documentation. It constructs an exemplary philosopher and provides a lens through which readers understand the Enneads.',
      'Porphyry was not merely submissive. Plotinus reportedly answered his questions at length, and their relation shows philosophical community working through correction. Porphyry’s presentation makes Plotinian ascent more institutionally transmissible: the teacher’s arguments belong to a life, a school, and a sequence of study. At the same time, later readers must distinguish Plotinus’ positions from Porphyry’s organization and interpretation. The student’s success makes that distinction difficult.'
    ],['neoplatonism','platonism'],['porphyry','plotinus'],['Life of Plotinus','Enneads']),
    section('enneads','Editing the Enneads',[
      'Plotinus wrote treatises in response to particular questions rather than composing one finished system. Porphyry collected fifty-four treatises, supplied titles, edited the text, and arranged them into six groups of nine, the Enneads. The arrangement moves broadly from ethical and human concerns through nature, soul, Intellect, and the One. It offers readers a path, but it does not preserve chronological development.',
      'This editorial act is philosophical. Grouping texts proposes relations among problems and suggests how ascent should be studied. A treatise gains meaning from its neighbors, while a title directs attention before reading begins. Porphyry also preserves chronology separately, allowing later scholars to compare order of composition with systematic order. The Enneads therefore demonstrate that transmission is interpretation: without Porphyry, Plotinus would be far less accessible, but the Plotinus we possess is inseparable from Porphyry’s map.'
    ],['neoplatonism','platonism'],['porphyry','plotinus'],['Enneads']),
    section('isagoge','The Isagoge and the problem of universals',[
      'Porphyry’s Isagoge introduces Aristotle’s Categories through five predicables: genus, species, difference, property, and accident. It teaches students how terms classify and relate to things. Near the beginning, Porphyry postpones difficult questions about whether genera and species exist independently, exist only in thought, and whether they are bodily or incorporeal. The refusal was extraordinarily productive.',
      'Medieval readers turned those postponed questions into the problem of universals. Realists, nominalists, and conceptualists disputed what shared natures are and how language and thought connect to reality. Porphyry’s compact introduction became a gateway to logic across Greek, Arabic, and Latin traditions. Its influence shows how philosophical importance can arise from framing a problem clearly rather than resolving it. The Isagoge teaches distinctions while marking where introductory logic reaches metaphysical controversy.'
    ],['logic','aristotelianism','medieval-scholasticism'],['porphyry','aristotle','boethius','ockham'],['Isagoge','Categories']),
    section('aristotle','Transmitting Aristotle within a Platonic curriculum',[
      'Porphyry helped establish the study of Aristotle’s logic as preparation for Platonic philosophy. This did not mean treating Plato and Aristotle as identical. Aristotelian analysis could discipline language and thought at the level of sensible and conceptual distinctions, while Platonism addressed higher metaphysical principles. The curriculum made apparent rivalry into an ordered educational relation.',
      'That arrangement influenced later Neoplatonic commentary and, through translation and adaptation, Islamic and medieval Latin philosophy. Students learned categories and predication before approaching more demanding questions of being and unity. The synthesis also risked smoothing real disagreements. Porphyry matters because he made the question of harmony itself productive: where do Aristotle’s tools apply, where does Plato’s metaphysics exceed them, and how can a curriculum teach the difference?'
    ],['neoplatonism','aristotelianism','logic'],['porphyry','plato','aristotle','boethius'],['Isagoge','Categories']),
    section('purification','Vegetarianism, asceticism, and purification',[
      'Porphyry treats philosophy as transformation of desire and attention, not textual expertise alone. In On Abstinence, he defends abstaining from animal food through ethical, religious, and ascetic considerations. Diet can reduce domination by appetite, avoid complicity in harm, and prepare the soul for contemplation. The arguments arise within ancient assumptions that require critical reading, but they make bodily practice part of philosophical reasoning.',
      'Purification does not simply express hatred of the body. It seeks freedom from forms of attachment that scatter attention and subordinate judgment to pleasure or custom. Yet ascetic ideals can become elitist or deny legitimate bodily needs. Porphyry’s practice raises a durable question: if philosophy aims to alter how a person perceives and acts, what habits support that change? His answer makes ethics, metaphysics, and daily consumption answerable to one another.'
    ],['neoplatonism','ethics','philosophy-of-religion'],['porphyry','plotinus'],['On Abstinence']),
    section('christianity','Religious controversy and Christianity',[
      'Porphyry wrote a substantial work Against the Christians, surviving only through fragments and responses by Christian authors. He challenged scriptural interpretation, chronology, prophecy, and claims to religious authority. The work belongs to a conflict in which philosophical schools and Christian thinkers disputed which texts, practices, and revelations could guide human return to the divine.',
      'Because opponents preserve much of the evidence, reconstruction requires caution. Porphyry should not be reduced to a persecutor or treated as a modern secular critic. His objections arise from a committed philosophical and religious alternative. Christian responses helped shape biblical interpretation and apologetics, while later suppression increased the work’s fragmentary status. The controversy reveals how textual criticism, metaphysics, and institutional power interact when traditions contest authority.'
    ],['neoplatonism','philosophy-of-religion'],['porphyry','augustine'],['Against the Christians']),
    section('iamblichus','Porphyry and Iamblichus on the limits of intellect',[
      'Iamblichus inherits Porphyry’s Neoplatonism while criticizing approaches that make intellectual contemplation too self-sufficient. The dispute appears in questions Porphyry addressed to an Egyptian priest and in the response associated with Iamblichus, On the Mysteries. If embodied souls are deeply dependent on divine causes, can reasoning and ethical purification alone complete ascent? Iamblichus argues that theurgy and divinely grounded ritual are necessary.',
      'The disagreement changes later Neoplatonism. Porphyry’s concerns about ritual credulity and philosophical standards meet Iamblichus’ claim that divine action exceeds human intellectual initiative. Neither side is captured by reason versus superstition. They dispute the metaphysics of mediation and the capacities of embodied agents. Porphyry thereby matters even where later thinkers reject him: his questions force theurgical Platonism to explain why ritual can possess philosophical efficacy.'
    ],['neoplatonism','philosophy-of-religion'],['porphyry','iamblichus','plotinus'],['On the Mysteries']),
    section('soul','Soul, embodiment, and the work of return',[
      'Porphyry treats the soul as capable of intellectual return yet entangled in habits, passions, and ways of imagining itself through the body. Philosophical liberation therefore requires more than accepting a metaphysical description. A person must reorder attention and desire so that the soul ceases to organize its life around bodily acquisition. This concern connects Porphyry’s ethical writings, his interpretation of Plotinus, and his practical recommendations. The soul’s origin and destiny become intelligible through a discipline that gradually makes the learner able to recognize them.',
      'The account clarifies why Porphyry can sound both world-denying and carefully ethical. Bodily existence is not simply dismissed as unreal; it is the condition in which choices reveal what the soul takes itself to be. Practices of restraint matter because they loosen dependencies that obscure intellectual activity. The philosophical question is whether such purification responsibly transforms embodied life or treats embodiment as an obstacle to be escaped. Later Platonists and Christian readers inherit both the aspiration and the tension.'
    ],['neoplatonism','ethics','philosophy-of-mind'],['porphyry','plotinus'],[]),
    section('commentary-method','Commentary, allegory, and disciplined interpretation',[
      'Porphyry’s work as an interpreter extends beyond summarizing doctrines. Late antique readers faced authoritative texts that appeared to disagree, contain myths, or address students at different levels. Commentary supplied tools for identifying a text’s aim, resolving apparent conflict, distinguishing literal from symbolic meaning, and locating a passage within a curriculum. Porphyry’s Homeric interpretation shows how inherited poetry could be read as encoding philosophical and religious insight rather than rejected as primitive story.',
      'This practice changes the unit of argument. A statement is assessed not only in isolation but through genre, pedagogical purpose, and its place within a larger tradition. The method can produce ingenious reconciliation, but it can also protect authority from criticism by explaining away difficulty. Porphyry therefore helps establish a durable interpretive problem: when does charitable reconstruction disclose a deeper coherence, and when does it impose a system that the source never possessed?'
    ],['neoplatonism','aesthetics','platonism'],['porphyry','plotinus','aristotle'],[]),
    section('ethics-community','Ethical formation, community, and philosophical authority',[
      'Porphyry’s philosophy addresses individuals, but it is not merely private spirituality. Diet, ritual participation, teaching, friendship, and textual study place the learner inside communities with inherited norms. The philosopher claims authority by distinguishing practices that purify from those that bind the soul more tightly to passion or error. Such judgments inevitably touch social identity and religious conflict, especially when Porphyry evaluates traditional sacrifice and Christian claims.',
      'His work invites a political question that Neoplatonic metaphysics can obscure: who decides which practices elevate and which degrade? The ideal of an ordered soul can support serious self-criticism, yet it can also rank lives and traditions according to standards controlled by an educated elite. Philosophy becomes transmissible through schools and disciplined communities, but those same structures determine whose experience counts as evidence of wisdom.'
    ],['ethics','political-philosophy','philosophy-of-religion'],['porphyry','iamblichus'],[]),
    section('philosophical-mediation','Why mediation is itself a philosophical achievement',[
      'Porphyry demonstrates that transmission is never neutral. Selecting, arranging, introducing, and commenting on works determine which problems later readers see and which relations appear natural. The Isagoge directs attention toward predication and universals; the Enneads make Plotinus appear as an ordered corpus; biography links arguments to an exemplary life. These activities do not merely package philosophy after the creative work is complete. They construct a durable environment in which inquiry can continue.',
      'That achievement also gives Porphyry unusual power over his inheritance. Later readers often meet Plotinus, Aristotle, and parts of Platonism through categories he helped stabilize. A mediator can preserve complexity or narrow it, clarify a dispute or silently settle it through organization. Reading Porphyry therefore trains attention on the intellectual infrastructure of tradition: curricula, editions, introductions, and interpretive habits are among the causes that shape philosophical history.'
    ],['neoplatonism','logic','platonism'],['porphyry','plotinus','aristotle'],['Isagoge','Life of Plotinus']),
    section('legacy-reading','Medieval transmission and how to read Porphyry',[
      'Porphyry’s logical influence extends through Boethius into medieval Latin education and through Greek and Arabic commentary traditions. The problem of universals, the organization of philosophical curriculum, and the relation between Aristotle and Plato all carry his imprint. His edition of Plotinus shaped Neoplatonism’s survival, while his ascetic and religious works disclose a thinker concerned with complete philosophical formation.',
      'Begin with the Life of Plotinus and Isagoge to see biography and logic functioning as philosophical mediation. Then compare the Enneads’ systematic arrangement with chronological information, and read selections from On Abstinence and religious controversies. The central question is what an organizer contributes to philosophy. Porphyry shows that preserving a tradition requires deciding its sequence, vocabulary, exemplary lives, boundaries, and relation to rivals; those decisions become arguments inherited by later centuries.'
    ],['neoplatonism','logic','medieval-scholasticism'],['porphyry','plotinus','boethius','iamblichus'],['Life of Plotinus','Isagoge','On Abstinence'])
  ],
  iamblichus:[
    section('overview','Neoplatonism becomes ritual, hierarchical, and embodied',[
      'Iamblichus transformed Neoplatonism by arguing that philosophical ascent cannot depend on intellectual contemplation alone. Human souls are embodied, limited, and situated within an ordered cosmos filled with divine powers. Return therefore requires theurgy: ritual action whose efficacy originates in the gods rather than in human technique. This claim makes religious practice part of metaphysics and changes the later Platonic tradition.',
      'Iamblichus is often caricatured as the thinker who replaced Plotinian philosophy with magic. That misses the argument. If divine causes exceed human intellect and are present throughout reality, material symbols and inherited rites may mediate a relation that reasoning cannot produce by itself. Theurgy is his answer to the limits of intellectual self-sufficiency, not an abandonment of philosophical explanation.'
    ],['neoplatonism','philosophy-of-religion','metaphysics'],['iamblichus','porphyry','plotinus'],['On the Mysteries']),
    section('after-plotinus','Neoplatonism after Plotinus and Porphyry',[
      'Plotinus organized reality through the One, Intellect, and Soul and emphasized inward contemplative return. Porphyry edited that inheritance, developed its curriculum, and raised questions about religious practice. Iamblichus accepts the broad Neoplatonic architecture while multiplying its mediations and emphasizing the soul’s distance from divine levels. Later Neoplatonism becomes more elaborate because it seeks to explain how every level participates in causes above it.',
      'This development is not simply decorative complication. A large gap between embodied individuals and the One creates explanatory problems. How do divine powers reach the sensible world? How can a soul whose reasoning is limited return beyond reason? Iamblichus introduces distinctions and ritual mediations to answer these questions. His work makes hierarchy operational: each level has characteristic powers, symbols, and modes of participation.'
    ],['neoplatonism','platonism','metaphysics'],['iamblichus','plotinus','porphyry','proclus'],[]),
    section('porphyry-dispute','The dispute with Porphyry',[
      'On the Mysteries responds to questions associated with Porphyry about Egyptian religion, divination, sacrifice, prayer, and theurgy. Writing under the persona of an Egyptian priest, Iamblichus challenges assumptions behind the questions. Porphyry appears to measure ritual by philosophical reasoning; Iamblichus argues that divine action cannot be contained by the intellectual standards of an embodied human investigator.',
      'The disagreement concerns agency. If ascent is achieved by the philosopher’s own understanding, salvation risks becoming an elite accomplishment. If divine symbols and rites work because gods graciously establish them, return depends first on higher causes. Critics can ask how authentic divine rites are distinguished from superstition or manipulation. Iamblichus must therefore explain ritual efficacy without making gods subject to human coercion. The dispute gives later Platonism a sophisticated philosophy of religious practice.'
    ],['neoplatonism','philosophy-of-religion'],['iamblichus','porphyry'],['On the Mysteries']),
    section('theurgy','Theurgy as divine action rather than mere magic',[
      'Theurgy literally suggests divine work. Ritual words, objects, gestures, and sacrifices are effective not because practitioners control gods but because divine powers have placed symbols of themselves throughout the cosmos. A rite activates or recognizes a relation already grounded in the divine order. Material things can participate in higher causes precisely because the sensible world is not abandoned by those causes.',
      'Calling theurgy mere magic erases this metaphysical account. Yet the distinction does not remove every concern. Claims of divinely authorized ritual can protect traditions from criticism and empower specialists. Iamblichus answers by placing efficacy in divine goodness and cosmic order rather than private will, but interpreters must still ask how practices are evaluated. The philosophical importance of theurgy lies in joining embodiment, symbol, community, and transcendence within one account of transformation.'
    ],['neoplatonism','philosophy-of-religion','metaphysics'],['iamblichus','proclus'],['On the Mysteries']),
    section('hierarchy','Divine hierarchy and metaphysical mediation',[
      'Iamblichus develops a more articulated hierarchy of divine beings and principles than Plotinus. Gods, intelligible orders, souls, and intermediate powers require distinctions because a single transition cannot explain every form of unity and multiplicity. Higher causes remain transcendent while being present through powers appropriate to lower levels. Mediation protects both divine otherness and the reality of participation.',
      'Such systems can seem remote because their many levels lack obvious modern equivalents. Their underlying problem remains recognizable: how can an ultimate cause be present in finite effects without becoming one finite cause among others? Iamblichus answers by distinguishing modes of causality and participation. The complexity also carries risk. Metaphysical hierarchy can be borrowed to naturalize social or institutional rank, even though an argument about causal dependence does not automatically justify human domination.'
    ],['neoplatonism','metaphysics','philosophy-of-religion'],['iamblichus','proclus','pseudo-dionysius'],[]),
    section('soul','Soul, embodiment, and limited self-sufficiency',[
      'Iamblichus places greater emphasis than Plotinus on the soul’s genuine descent and embodied limitation. The human soul does not remain wholly undescended at the intelligible level in a way that makes return primarily recognition of its highest self. Embodiment affects the soul’s condition deeply, and intellectual activity cannot simply leap beyond the order in which it is situated.',
      'This account motivates theurgy and communal ritual. The whole embodied person needs forms of participation that reach beyond discursive thought. It also resists a philosophical ideal in which the intellectual elite saves itself through private contemplation. Yet dependence on divine mediation may appear to reduce autonomy. Iamblichus reframes freedom as alignment with causes that make the soul capable of fulfillment, rather than independence from every relation beyond itself.'
    ],['neoplatonism','philosophy-of-mind','philosophy-of-religion'],['iamblichus','plotinus'],[]),
    section('pythagoreanism','Pythagoras, education, and a sacred philosophical lineage',[
      'Iamblichus wrote a Life of Pythagoras and treated Pythagoreanism as a model joining mathematics, ethical discipline, community, ritual, and divine wisdom. Pythagoras becomes more than an early thinker with doctrines about number. He represents a philosophical life whose practices prepare students for truth and whose authority anchors a sacred lineage.',
      'This use of Pythagoras shows how late antique schools constructed ancestry. Biography, sayings, and communal rules establish an educational ideal as well as historical claims. Modern readers must distinguish evidence about early Pythagoreanism from Iamblichus’ later program. Even so, the work clarifies his project: philosophy succeeds when intellectual study, character, ritual, and community form one path rather than competing activities.'
    ],['neoplatonism','ancient-greek','ethics'],['iamblichus','pythagoras'],['Life of Pythagoras']),
    section('plato-practice','Plato, curriculum, and religious interpretation',[
      'Iamblichus helped shape a curriculum in which Platonic dialogues guide progressive philosophical formation. Texts are not only sources of propositions; their order and interpretive level train the soul. Mathematical study, ethical purification, theology, and ritual belong to a coordinated ascent. Plato’s myths and religious language therefore receive systematic significance rather than being dismissed as poetic decoration.',
      'This approach influences later commentary traditions, especially Proclus. It can reveal dimensions of Plato ignored by purely doctrinal readings, but it can also impose a later system on dialogues whose voices remain open and dramatic. Iamblichus’ interpretive practice asks whether reading itself can be transformative and whether a canon’s sequence embodies a theory of education. The question remains relevant wherever curricula claim to shape judgment rather than merely transfer information.'
    ],['neoplatonism','platonism','ancient-greek'],['iamblichus','plato','proclus'],['Timaeus','Parmenides']),
    section('influence','Influence on Proclus and later religious Platonisms',[
      'Proclus inherits Iamblichus’ elaborate mediation, theurgical practice, and conviction that Platonic theology can be systematized. Later pagan Platonists use these resources to defend philosophical religious life under Christian imperial conditions. Christian authors transform hierarchy, participation, symbol, and return, while Islamic and Renaissance Platonisms encounter related structures through complex routes of translation and reception.',
      'Influence does not mean agreement. Christian creation and liturgy, Islamic accounts of divine unity, and Renaissance projects revise the metaphysical meaning of ritual and hierarchy. Iamblichus matters because he makes it difficult to separate philosophy of religion from embodied practice. A theory of the divine must explain not only what first principles are but how finite people, symbols, communities, and traditions can responsibly relate to them.'
    ],['neoplatonism','philosophy-of-religion'],['iamblichus','proclus','pseudo-dionysius'],[]),
    section('knowledge','Knowledge, revelation, and the limits of human reasoning',[
      'Iamblichus does not reject reasoning. His elaborate distinctions and defenses of ritual presume rigorous argument. He does, however, deny that discursive reasoning alone can bridge every distance between the human soul and divine causes. Human thought begins from a divided and embodied condition; the gods do not. Knowledge of divine realities therefore depends partly on manifestations and practices initiated from above rather than achievements generated entirely by an autonomous intellect.',
      'This position changes the meaning of philosophical humility. For Porphyry, purification can appear to free intellect for its own ascent. Iamblichus emphasizes that ascent succeeds through a prior divine generosity that ritual makes present. The view raises enduring questions about reason and revelation. Can a practice disclose realities that argument cannot reach? How can such disclosure be distinguished from error or manipulation? Iamblichus answers through an ordered tradition of symbols, but the need to justify that order never disappears.'
    ],['epistemology','philosophy-of-religion','neoplatonism'],['iamblichus','porphyry'],['On the Mysteries']),
    section('symbols','Symbols, material things, and divine presence',[
      'Theurgy depends on symbols whose efficacy is not reducible to what practitioners consciously understand. Stones, plants, names, sounds, and ritual actions can participate in divine series because reality is structured through correspondences extending from gods to material effects. Material things are therefore not simply at the bottom of a ladder to be abandoned. Under appropriate conditions, they disclose and mediate powers that exceed the individual soul’s intention.',
      'This symbolic realism distinguishes Iamblichus from approaches that treat ritual primarily as psychological concentration or allegorical instruction. It also creates a difficult standard of interpretation. If symbols work through objective divine connections, how are authentic correspondences identified? Tradition, priestly knowledge, and philosophical classification become crucial, but each can be contested. The resulting philosophy gives embodiment a positive religious role while exposing practitioners to strong claims of specialized authority.'
    ],['philosophy-of-religion','metaphysics','neoplatonism'],['iamblichus','porphyry','proclus'],['On the Mysteries']),
    section('ethics-community','Virtue, education, and the philosophical community',[
      'Iamblichus situates ethical formation within a graded program. Ordinary civic virtues regulate passions and action; higher purificatory and contemplative virtues turn the soul toward intellect and divine causes. The stages do not make practical ethics irrelevant. They show how different forms of excellence answer to different levels of human development. Education must meet learners where they are while orienting them toward a more comprehensive order.',
      'His communities also relied on exemplary lineages. Pythagorean biographies and rules portray philosophy as a shared way of life sustained by friendship, discipline, reverence, and ordered teaching. Such communities can preserve demanding practices that isolated readers could not maintain. They can also make hierarchy appear naturally wise. Iamblichus forces readers to examine both sides: transformation needs social forms, yet every form that claims to guide transformation requires standards of accountability.'
    ],['ethics','political-philosophy','neoplatonism'],['iamblichus','pythagoras','proclus'],['Life of Pythagoras']),
    section('embodied-agency','What the embodied soul can and cannot do',[
      'The dispute over theurgy turns on a diagnosis of human agency. If the highest part of the soul remains continuously united with intellect, as some readings of Plotinus suggest, philosophical recollection might be enough to recover its true life. Iamblichus gives embodiment greater weight. The descended soul is genuinely affected by its condition and cannot simply think itself free through an act of inward concentration.',
      'This limitation is not a counsel of despair. It explains why transformation requires multiple forms of assistance: ethical habituation, mathematical education, prayer, symbols, teachers, and divine action. The result is a relational picture of agency in which dependence can enable rather than cancel freedom. Modern readers need not accept the metaphysics to recognize the challenge: theories of self-transformation become shallow when they ignore the bodily, social, and inherited conditions under which a self acts.'
    ],['philosophy-of-mind','ethics','neoplatonism'],['iamblichus','plotinus','porphyry'],[]),
    section('reading','How to read Iamblichus',[
      'Begin with selections from On the Mysteries focused on theurgy, prayer, symbols, and divine action. Read Porphyry’s questions alongside the response so the dispute remains visible. Then approach the Life of Pythagoras as a late antique construction of philosophical education, not transparent evidence for the historical Pythagoras. Compare Iamblichus with Plotinus on soul and ascent and with Proclus on mediation.',
      'Keep three cautions in view. Theurgy is not simply magical coercion. Hierarchy of causes does not automatically justify social hierarchy. Elaborate metaphysics is attempting to solve problems of participation and distance rather than merely multiplying entities. The central question is whether intellectual understanding can transform embodied human beings by itself. Iamblichus’ negative answer forces philosophy to account for ritual, dependency, and communal practice.',
      'Read slowly enough to notice that his most unfamiliar claims arise from a consistent diagnosis of human limitation.'
    ],['neoplatonism','philosophy-of-religion','platonism'],['iamblichus','porphyry','plotinus','proclus'],['On the Mysteries','Life of Pythagoras'])
  ],
  proclus:[
    section('overview','The great systematizer of late Neoplatonism',[
      'Proclus led the Athenian Platonic school in the fifth century and produced one of antiquity’s most elaborate philosophical systems. He wrote commentaries on Plato, systematic works such as the Elements of Theology and Platonic Theology, mathematical commentary, hymns, and religious texts. His project organizes how every level of reality remains in its cause, proceeds from it, and returns toward it.',
      'The system can initially appear remote because it includes the One, henads, intelligible orders, souls, divine series, and many forms of mediation. Its driving questions are precise: how can unity cause plurality without losing unity, how can effects participate in causes, and how can causes be present without becoming divided among effects? Proclus matters because he turns those problems into a rigorous architecture inherited by multiple traditions.'
    ],['neoplatonism','metaphysics','platonism'],['proclus','iamblichus','plotinus'],['Elements of Theology','Platonic Theology']),
    section('athens','The Athenian school and philosophy as a complete life',[
      'Proclus studied and taught in Athens, where the Platonic school combined textual commentary, mathematics, metaphysics, ethics, and religious practice. As head of the school, he inhabited an institution claiming continuity with Plato while operating in an increasingly Christian empire. Philosophy was both intellectual discipline and a form of pagan religious identity.',
      'His biography portrays intense study, teaching, ritual observance, hymn writing, and civic involvement. Such portraits idealize their subject, but they show how the school understood philosophical authority. Systematic knowledge had to be embodied in a life ordered toward divine causes. The institutional setting also explains Proclus’ productivity: commentaries trained students, systematic works clarified principles, and ritual integrated intellectual ascent with inherited religious practice.'
    ],['neoplatonism','platonism','ancient-greek'],['proclus','plato'],[]),
    section('inheritance','Plotinus, Iamblichus, and the inherited problem',[
      'Plotinus established the One, Intellect, and Soul as a powerful account of dependence and return. Iamblichus multiplied mediations and defended theurgy because embodied souls cannot rely on intellect alone. Proclus inherits both and seeks greater systematic precision. He explains how levels unfold through recurring causal structures while preserving the transcendence of higher principles.',
      'This is not merely accumulation. Every added distinction answers a problem about continuity and difference. If the One is wholly simple, how can diverse divine and intelligible orders arise? If a cause remains undiminished, how is it genuinely present in effects? Proclus’ system makes mediation central rather than embarrassing. It also preserves Iamblichean ritual: intellectual explanation and theurgical participation address different dimensions of return.'
    ],['neoplatonism','metaphysics','philosophy-of-religion'],['proclus','plotinus','iamblichus'],[]),
    section('elements','The Elements of Theology and geometrical exposition',[
      'The Elements of Theology presents a sequence of propositions with demonstrations, beginning from unity and causation and developing a Neoplatonic metaphysics. Its form resembles geometrical proof: each proposition depends on earlier principles, making the system’s architecture visible. The work does not narrate myths or comment directly on a dialogue; it attempts to display necessary relations among causes, participants, intellects, souls, and divine unities.',
      'The method gives readers unusual access to late Neoplatonic reasoning. It also raises questions about whether first principles can truly be demonstrated from such starting points and whether systematic clarity conceals interpretive choices. The work’s later influence was immense, including through adaptations such as the Arabic Book of Causes. Proclus shows how metaphysics can seek formal order without becoming modern mathematics or abandoning religious meaning.'
    ],['neoplatonism','metaphysics','logic'],['proclus','aristotle'],['Elements of Theology']),
    section('remaining','Remaining, procession, and return',[
      'Proclus organizes causality through a triad: every effect remains in its cause, proceeds from it, and returns toward it. Remaining preserves continuity and dependence; procession explains genuine distinction and multiplicity; return describes the effect’s orientation toward the source that completes it. None of these is simply a temporal event. They identify simultaneous dimensions of causal relation.',
      'The triad prevents creation from being imagined as separation that leaves the source behind. An effect can possess its own activity while remaining dependent, and return need not erase difference. The pattern recurs across levels of reality, giving the system both unity and complexity. It later influences metaphysical and theological accounts of exit and return. Critics can ask whether the triad explains dependence or imposes one pattern too widely, but its analytical power is clear.'
    ],['neoplatonism','metaphysics'],['proclus','plotinus','pseudo-dionysius'],['Elements of Theology']),
    section('henads','Henads, the One, and divine plurality',[
      'The One is beyond being and cannot itself contain differentiated plurality. Proclus introduces henads, divine unities through which the first principle’s causality is participated in distinct series. Henads help explain how a plurality of gods and orders can depend on absolute unity without reducing divinity to one level of Intellect.',
      'The doctrine is difficult because each henad must be genuinely one while belonging to a plurality. Proclus uses it to integrate traditional gods with Platonic metaphysics and to mediate between the ineffable One and intelligible determination. Modern readers need not accept the theology to recognize the problem: how can one source ground distinct causal powers without becoming a collection? Henads are Proclus’ systematic answer to unity expressed without division.'
    ],['neoplatonism','metaphysics','philosophy-of-religion'],['proclus','iamblichus'],['Platonic Theology']),
    section('participation','Participation, causality, and mediation',[
      'Proclus distinguishes what is participated, what participates, and the unparticipated source that can cause many effects without being divided among them. This framework explains how a property or power is present in multiple things while remaining grounded in a cause beyond any one instance. Participation is neither identity nor external resemblance; it is a structured dependence.',
      'The account influenced later debates about universals, divine ideas, causality, and hierarchy. It also invites objections. Multiplying mediating terms can seem to postpone explanation, and claims about unparticipated causes require justification. Proclus responds by showing how each distinction protects a feature that simpler accounts lose: transcendence, presence, plurality, or causal unity. His system matters as a sustained theory of mediation rather than a catalogue of levels.'
    ],['neoplatonism','metaphysics','ontology'],['proclus','plato','pseudo-dionysius'],['Elements of Theology']),
    section('commentary','Commentaries, mathematics, and reading Plato systematically',[
      'Proclus’ commentaries on dialogues such as the Timaeus and Parmenides combine close textual interpretation with extensive metaphysical construction. A passage can disclose principles operating across the whole Platonic system. Commentary is therefore creative philosophy: explaining Plato requires deciding how cosmology, theology, soul, mathematics, and dialectic fit together.',
      'His commentary on Euclid also preserves mathematical history and examines the status of mathematical objects and demonstration. Mathematics occupies a mediating role between sensible multiplicity and intelligible structure. Proclus’ range resists a division between mystical theology and rigorous reasoning. He seeks an ordered curriculum in which each science trains capacities appropriate to its objects and contributes to philosophical return.'
    ],['neoplatonism','platonism','aristotelianism'],['proclus','plato'],['Timaeus','Parmenides','Elements of Theology']),
    section('reception','From Pseudo-Dionysius to medieval and modern metaphysics',[
      'Pseudo-Dionysius adapts Proclean procession, return, hierarchy, participation, and negative theology within Christianity. The Book of Causes transmits a transformed Proclean metaphysics into Arabic and Latin traditions. Medieval philosophers engage structures whose precise source was not always known, while Renaissance Platonists recover and reinterpret Proclus directly. His causal language also attracts later idealist and metaphysical readers.',
      'These receptions alter the system. Creation, revelation, monotheism, incarnation, and different accounts of individuality cannot simply be added to Proclus unchanged. His influence often works through selective transformation or mistaken attribution. That history demonstrates why Proclus matters: he supplied an exceptionally precise vocabulary for how finite plurality depends on transcendent unity, a vocabulary flexible enough to travel into traditions with sharply different commitments.'
    ],['neoplatonism','philosophy-of-religion','medieval-scholasticism'],['proclus','pseudo-dionysius','aquinas'],['Elements of Theology','Mystical Theology']),
    section('dialectic','Dialectic, demonstration, and the architecture of a system',[
      'Proclus’ systematic reputation does not mean that every truth is deduced from a single premise without interpretation. His works combine formal propositions, commentary, prayer, mythic interpretation, and polemic. The Elements of Theology displays relations among causes in a compressed demonstrative sequence, while the Platonic Theology and commentaries identify the same structures through dialogues and inherited religious traditions. Different genres make different dimensions of the system available.',
      'This combination shows what system-building demands. A system must organize claims, explain transitions, answer objections, and show why apparently different authorities belong together. Its strength is explanatory coordination: questions about unity, intellect, soul, mathematics, and religion illuminate one another. Its danger is over-integration, since disagreement or textual irregularity may be assigned a place that preserves the whole. Proclus remains a model for both the ambition and vulnerability of systematic philosophy.'
    ],['logic','metaphysics','neoplatonism'],['proclus','plato','aristotle'],['Elements of Theology','Platonic Theology']),
    section('evil-providence','Evil, providence, and freedom within an ordered cosmos',[
      'A highly ordered metaphysics faces an obvious challenge: if all causes proceed from and return toward the Good, how can evil and failure occur? Proclus treats evil as parasitic rather than an independent principle. It arises through partial goods, limited recipients, and disordered relations, not from a positive source opposed to goodness. This preserves the causal priority of the Good while requiring a detailed account of how finite agencies can miss their proper order.',
      'Providence does not erase agency. Souls act from their own level and can direct themselves badly even while remaining dependent on higher causes. The resulting account tries to hold together cosmic intelligibility, divine care, and responsibility. Critics may ask whether a system in which every level is comprehensively ordered leaves enough room for genuine contingency or suffering that cannot be redescribed as limited participation. Proclus makes that tension explicit rather than solving it cheaply.'
    ],['metaphysics','ethics','philosophy-of-religion'],['proclus','plotinus'],[]),
    section('soul-time','Soul, time, and the movement between worlds',[
      'Soul occupies a pivotal position in Proclus because it is both intelligible and capable of temporal movement. Unlike intellect, which grasps its objects in an undivided way, soul unfolds thought and activity through sequence. This helps explain time as more than a neutral container: temporal order expresses a mode of life associated with soul and cosmos. Human reasoning, memory, choice, and return all bear this unfolded character.',
      'The soul’s intermediate status makes education possible. Because it participates in intelligible causes, it can recognize order and turn upward; because it operates through divided activities, it can become scattered. Mathematics and dialectic train the learner to move from multiplicity toward intelligible relations without pretending that embodied cognition has already become divine intellect. Proclus thereby connects metaphysics to pedagogy: the structure of reality explains both why learning is difficult and why transformation is possible.'
    ],['philosophy-of-mind','metaphysics','neoplatonism'],['proclus','plato'],['Commentary on the Timaeus']),
    section('religious-practice','Prayer, theurgy, and philosophical life',[
      'Proclus’ rigorous metaphysics belongs to a religious life that included hymns, prayer, ritual, and devotion to multiple divine traditions. These practices are not incidental concessions to custom. Within his system, beings return through the causes and symbols that connect them to higher series. Theurgy and prayer express dependence on divine initiative while aligning the participant with an order that discursive thought alone does not create.',
      'The conjunction unsettles modern divisions between rational philosophy and religion. Proclus can demand exact argument while holding that the highest relation exceeds demonstration. Readers must neither erase the ritual setting nor use it to dismiss the arguments. The more productive question is how forms of reasoning and practice support, limit, or challenge one another within a complete conception of philosophical life.'
    ],['philosophy-of-religion','neoplatonism','ethics'],['proclus','iamblichus'],['Hymns']),
    section('reading','Why Proclus matters and how to read him',[
      'Begin with selected propositions from the Elements of Theology, tracing how each depends on previous claims. Then read commentary selections to see how systematic principles arise through interpretation of Plato. Compare Proclus with Plotinus on simplicity and with Iamblichus on mediation and theurgy. Finally follow one reception route through Pseudo-Dionysius or the Book of Causes.',
      'Proclus matters even when his hierarchy seems implausible because he refuses to use words such as participation, cause, or transcendence vaguely. Each relation receives distinctions and consequences. The system asks what an explanation must preserve when one reality depends on another: difference, presence, power, and return. Modern readers can reject the architecture while learning from its insistence that metaphysical mediation must be explained rather than merely named.',
      'A useful reading practice is to diagram one causal sequence and ask what each added distinction accomplishes. Then test whether the distinction genuinely explains dependence or merely relocates the original difficulty. This keeps the architecture visible without granting it automatic authority and reveals why later thinkers could transform selected Proclean relations even when they rejected his wider theology.'
    ],['neoplatonism','metaphysics','platonism'],['proclus','plotinus','iamblichus','pseudo-dionysius'],['Elements of Theology','Platonic Theology'])
  ],
  'pseudo-dionysius':[
    section('overview','Christian Neoplatonism under apostolic authority',[
      'Pseudo-Dionysius is the name given to the late fifth- or early sixth-century Christian author who wrote as Dionysius the Areopagite, the Athenian convert mentioned in Acts. The works join Christian scripture, liturgy, angels, and ecclesiastical order to a deeply Neoplatonic language of divine names, participation, procession, return, hierarchy, and negation. Their enormous influence depended on both philosophical power and the belief that they came from an apostolic-era witness.',
      'Modern scholarship recognizes the pseudonymous identity partly because the texts depend on late Neoplatonic thought, especially Proclus. The discovery changes historical interpretation without making the works philosophically empty. Pseudo-Dionysius created a distinctive Christian synthesis whose account of how language reaches and fails before God shaped medieval metaphysics, mysticism, liturgy, and philosophy of religion.'
    ],['philosophy-of-religion','neoplatonism','metaphysics'],['pseudo-dionysius','proclus','augustine'],['Divine Names','Mystical Theology']),
    section('identity','The identity problem and the force of pseudonymity',[
      'The author presents himself as Dionysius converted by Paul in Athens, placing the corpus near apostolic origins. For centuries this identity gave the works extraordinary authority. A text apparently joining Pauline Christianity to sophisticated Platonism could seem to prove that the metaphysical synthesis belonged near the beginning of the tradition rather than emerging through late antique development.',
      'Pseudonymity raises ethical and interpretive questions. Ancient and late antique pseudonymous writing could claim a lineage or voice rather than function exactly like modern forgery, yet the assumed identity clearly amplified authority. Once the dating changed, readers could see the corpus responding to Proclus and late antique institutions. The identity problem therefore belongs to the philosophy: how does authority affect assent, and how should insights be evaluated when the historical claim supporting their reception proves false?'
    ],['philosophy-of-religion','neoplatonism','epistemology'],['pseudo-dionysius','proclus'],[]),
    section('christian-neoplatonism','A Christian transformation of late Neoplatonism',[
      'Pseudo-Dionysius adopts Neoplatonic structures while revising them through Christian commitments. All things proceed from divine goodness, possess being through participation, and return toward their source. God exceeds being and knowledge, yet is named through scriptural revelations and the perfections visible in creatures. Hierarchies mediate illumination through ordered relations.',
      'This is not Proclus with Christian vocabulary substituted. Creation, scripture, Christ, angels, sacraments, and church order change the setting and meaning of procession and return. At the same time, the depth of Proclean influence complicates claims that the synthesis is simply apostolic teaching. The corpus demonstrates philosophical transformation: inherited concepts become capable of organizing a different theological world while retaining tensions from their source.'
    ],['philosophy-of-religion','neoplatonism','platonism'],['pseudo-dionysius','proclus','plotinus'],['Divine Names']),
    section('negative-theology','Apophatic theology and the limits of language',[
      'Negative or apophatic theology denies that ordinary predicates capture God as God is. God is not one being among beings and cannot be enclosed by concepts derived from finite effects. The Mystical Theology moves through affirmations and negations toward a darkness beyond discursive knowledge. Negation is not the claim that nothing is real; it protects transcendence from the idolatry of treating a concept as the divine itself.',
      'Yet Pseudo-Dionysius also uses abundant names and symbols. God is called good, being, life, wisdom, and love because creatures participate in gifts that originate in the divine. Affirmation, negation, and a movement beyond both belong together. The philosophical challenge is whether language can be meaningful about what exceeds every concept. Dionysian apophasis answers that effects disclose their source truly but incompletely, and that disciplined unsaying corrects the limits of every saying.'
    ],['philosophy-of-religion','metaphysics','neoplatonism'],['pseudo-dionysius','proclus','maimonides'],['Mystical Theology','Divine Names']),
    section('divine-names','Divine names, symbols, and participation',[
      'The Divine Names examines scriptural names not as definitions of God’s essence but as ways divine causality is manifested in creatures. Goodness, beauty, being, life, wisdom, and power name gifts through which finite realities participate in their source. Because the cause exceeds each effect, no name is exhaustive. Because effects genuinely depend on the cause, names are not arbitrary.',
      'Symbolic theology extends this logic to images that appear unsuitable or even shocking. Material and scriptural symbols can redirect attention precisely because their inadequacy prevents a reader from confusing image with divine reality. Interpretation becomes a practice of ascent from symbol through meaning toward a source beyond representation. This account influenced sacramental, aesthetic, and hermeneutic traditions while raising questions about who possesses authority to interpret symbols correctly.'
    ],['philosophy-of-religion','neoplatonism','aesthetics'],['pseudo-dionysius','proclus'],['Divine Names']),
    section('hierarchy','Hierarchy as mediated illumination',[
      'For Pseudo-Dionysius, hierarchy is a sacred order through which beings receive and communicate divine illumination according to their capacities. The Celestial Hierarchy orders angelic ranks, while the Ecclesiastical Hierarchy interprets church ministries and rites. Higher members receive and transmit; lower members are raised through mediation. Hierarchy therefore joins metaphysics, pedagogy, liturgy, and institution.',
      'The concept is powerful and dangerous. It explains how transcendent goodness can be present through finite relations and how reception can become service to others. It can also sacralize unequal institutions and make criticism appear rebellion against divine order. Interpreters must distinguish a metaphysics of mediated participation from any automatic justification of existing rank. The tension between illumination and domination is central to the corpus’s political and institutional legacy.'
    ],['philosophy-of-religion','neoplatonism','political-philosophy'],['pseudo-dionysius','proclus'],['Celestial Hierarchy','Ecclesiastical Hierarchy']),
    section('procession-return','Procession, return, and mystical ascent',[
      'Dionysian metaphysics describes divine goodness as going out toward creatures without leaving itself and drawing creatures back toward their source. Procession explains gift and participation; return explains desire, purification, illumination, and union. The pattern transforms late Neoplatonic causality within a Christian account of creation and worship.',
      'Mystical ascent is not merely a private feeling. It is prepared through ethical purification, scriptural symbols, liturgy, communal mediation, affirmation, and negation. The final movement beyond concepts depends on practices and doctrines that concepts helped articulate. This creates an enduring tension: if union exceeds language and institution, what authority do theological systems retain? If ascent requires ordered mediation, how free can mystical experience be from institutional control?'
    ],['philosophy-of-religion','neoplatonism','metaphysics'],['pseudo-dionysius','proclus','plotinus'],['Mystical Theology']),
    section('creation','Creation, causality, and the Christian difference',[
      'Dionysian language of procession can resemble Neoplatonic emanation, but the Christian setting changes its implications. Creatures do not complete a deficient source, and divine generosity is not one event inside a larger cosmic process. All finite being depends on a cause that exceeds the order it gives. The corpus often emphasizes participation and return rather than offering a separate technical treatise on creation, which allows later interpreters to debate how fully its metaphysics expresses distinctively Christian commitments.',
      'The issue matters because causal language shapes religious practice. If creatures are genuine gifts, material and social realities can mediate divine goodness without becoming divine by nature. If transcendence is radical, no mediator can contain or control the source. Dionysian thought holds these claims together through hierarchy and symbolism. Later readers disagree about whether that synthesis honors creaturely difference or subordinates finite realities too completely to a vertical order.'
    ],['philosophy-of-religion','metaphysics','neoplatonism'],['pseudo-dionysius','proclus','aquinas'],['Divine Names']),
    section('love-beauty','Divine eros, beauty, and ecstatic movement',[
      'The Divine Names describes goodness and beauty as drawing beings beyond self-enclosure toward their source and toward one another. Dionysius can use the language of eros for divine and creaturely movement, carefully redefining a term that might seem too passionate for transcendent theology. Love is ecstatic because the lover does not remain closed within the self. At every level, desire reveals dependence on a good that the desiring being does not simply possess.',
      'This account joins aesthetics, ethics, and metaphysics. Beauty is not merely pleasing appearance; it gathers multiplicity into proportion and calls beings toward participation. Yet the language can become dangerously abstract if concrete loves and injuries disappear into cosmic harmony. Reading Dionysius well requires asking how ecstatic love changes action and relation, not only how it describes ascent. The tradition’s strongest interpreters use transcendence to deepen responsibility rather than evade the finite world.'
    ],['aesthetics','ethics','philosophy-of-religion'],['pseudo-dionysius','plato'],['Divine Names']),
    section('liturgy-politics','Liturgy, institution, and the politics of mediation',[
      'The Ecclesiastical Hierarchy interprets rites, offices, and communal practices as forms of purification, illumination, and perfection. Knowledge is enacted through initiation and participation, not possessed only as private theory. This makes Dionysian philosophy unusually attentive to how symbols, bodies, words, and social roles educate perception. A community can train members to see ordinary materials as bearers of meaning extending beyond themselves.',
      'The same structure raises political concerns. When institutional rank is presented as an image of divine order, disagreement may be dismissed as spiritual immaturity. Mediation can serve others by communicating what it receives, or it can become a claim to monopolize access. The corpus does not settle this problem for modern readers. It supplies a framework whose ethical quality depends on whether hierarchy remains accountable to generous illumination or hardens into self-protective power.'
    ],['political-philosophy','philosophy-of-religion','ethics'],['pseudo-dionysius','aquinas'],['Ecclesiastical Hierarchy']),
    section('knowledge-unknowing','Knowing through unknowing',[
      'Dionysian unknowing is not simple ignorance and not a rejection of study. The reader moves through names, arguments, symbols, and ordered practices before recognizing that none encloses the divine source. The failure of concepts at their limit can therefore be an achievement of disciplined knowledge. One learns not merely that a proposition is false, but why every finite mode of representation remains dependent and incomplete.',
      'This makes apophasis both intellectually demanding and difficult to regulate. Claims to experience what exceeds language may resist ordinary criticism, while purely conceptual criticism may miss the practice being described. The corpus responds by joining unknowing to inherited texts, liturgy, and ethical purification, yet those authorities also require examination. Its lasting value lies in keeping epistemic humility connected to serious inquiry rather than treating mystery as an excuse to stop thinking.'
    ],['epistemology','philosophy-of-religion','metaphysics'],['pseudo-dionysius','proclus'],['Mystical Theology']),
    section('proclus','Proclus and the transformation of late Neoplatonism',[
      'Close parallels in structure and language connect Pseudo-Dionysius to Proclus. Participation, causal transcendence, procession and return, hierarchical mediation, and negative theology all reflect late Neoplatonic developments. This dependence helped scholars date the corpus later than its claimed apostolic identity. It also reveals the author as a highly skilled philosophical transformer rather than a writer using vague Platonic decoration.',
      'Differences matter as much as parallels. Proclean henads and pagan theology do not simply remain under Christian names. Scripture, creation, Christ, angels, and ecclesiastical rites reorganize the system. Studying the relation prevents two mistakes: treating Dionysius as purely original Christian mysticism or treating him as disguised Proclus. His achievement lies in making a Neoplatonic causal grammar serve a Christian symbolic and liturgical world.'
    ],['neoplatonism','philosophy-of-religion'],['pseudo-dionysius','proclus'],['Elements of Theology','Divine Names']),
    section('reception','From Maximus and Eriugena to scholasticism and mysticism',[
      'Maximus the Confessor interpreted the Dionysian corpus within Byzantine Christianity, while John Scotus Eriugena translated and developed it in the Latin West. Scholastic thinkers, including Aquinas, treated Dionysius as an important theological authority. The works shaped accounts of divine naming, angelic order, participation, causation, and the limits of knowledge. Their assumed apostolic origin magnified their authority.',
      'Meister Eckhart and other mystical traditions drew on Dionysian negation and return, while modern philosophy of religion continues to debate apophatic language. Reception was never uniform. Thinkers integrated the corpus with different doctrines of creation, grace, intellect, and institution. The history shows how pseudonymous authority and philosophical usefulness can reinforce one another, and how a text can remain generative after its claimed identity is rejected.'
    ],['philosophy-of-religion','medieval-scholasticism','neoplatonism'],['pseudo-dionysius','aquinas'],['Mystical Theology','Divine Names']),
    section('reading','Interpretive tensions and how to read the corpus',[
      'Read the Mystical Theology beside the Divine Names so negation is not mistaken for silence without affirmation. Read the two Hierarchies to see that mystical ascent is embedded in liturgy and institution. Compare key passages with Proclus, then follow a reception route through Maximus, Eriugena, Aquinas, or Eckhart. Keep the pseudonymous identity visible because it shaped both composition and authority.',
      'Pseudo-Dionysius matters for philosophy of religion because the corpus presses several questions at once. How can finite language refer to a transcendent source? Can symbols reveal through their inadequacy? Does mediation enable participation or authorize domination? Can union exceed concepts without making reasoning irrelevant? The works refuse to separate metaphysics, language, ritual, and institutional order, which is precisely why their influence remains both powerful and contested.',
      'Their difficulty is therefore part of the lesson: every account of transcendence also organizes finite speech and authority.'
    ],['philosophy-of-religion','neoplatonism','metaphysics'],['pseudo-dionysius','proclus','aquinas'],['Mystical Theology','Divine Names','Celestial Hierarchy'])
  ]
};
